// Get EPR data and outreach log from merged inputs
const allInputs = $input.all();
const eprData = [];
const outreachLog = [];

// Separate the merged data
for (const item of allInputs) {
  if (item.json['MEMBER NAME'] !== undefined) {
    eprData.push(item.json);
  } else if (item.json['station_code'] !== undefined || item.json['member_name'] !== undefined) {
    outreachLog.push(item.json);
  }
}

const THRESHOLD = 90;
const COOLDOWN_DAYS = 30;
const MAX_PER_RUN = 30; // Max to process - 30 allows up to 10 per rep (3 reps)

// Build set of recently contacted station codes
const now = new Date();
const recentlyContacted = new Set();

for (const log of outreachLog) {
  const sentAt = log.sent_at || log.processed_at || log.failed_at;
  if (sentAt && log.station_code) {
    const logDate = new Date(sentAt);
    const daysSince = (now - logDate) / (1000 * 60 * 60 * 24);
    if (daysSince <= COOLDOWN_DAYS) {
      recentlyContacted.add(log.station_code);
    }
  }
}

// Filter EPR data
const candidates = [];

for (const row of eprData) {
  const memberName = row['MEMBER NAME'] || '';
  const stationCode = row['STATION CODE'] || '';
  const ticketsReceived = parseInt(String(row['TICKETS RECEIVED'] || '0').replace(/,/g, ''), 10) || 0;
  const responsesNeeded = parseInt(String(row['RESPONSES NEEDED'] || '0').replace(/,/g, ''), 10) || 0;
  const totalResponsesSent = parseInt(String(row['TOTAL RESPS SENT'] || '0').replace(/,/g, ''), 10) || 0;

  let responseRate;
  const rateRaw = row['% RESPONDED'];
  if (rateRaw !== undefined && rateRaw !== null && rateRaw !== '') {
    responseRate = parseFloat(String(rateRaw).replace('%', ''));
  } else if (responsesNeeded > 0) {
    responseRate = Math.round((totalResponsesSent / responsesNeeded) * 100);
  } else {
    responseRate = 100;
  }

  // Skip if no station code or member name
  if (!stationCode || !memberName) continue;

  // Skip if compliant
  if (responseRate >= THRESHOLD) continue;

  // Skip if no responses needed
  if (responsesNeeded === 0) continue;

  // Skip if recently contacted
  if (recentlyContacted.has(stationCode)) continue;

  candidates.push({
    json: {
      member_name: memberName,
      station_code: stationCode,
      tickets_received: ticketsReceived,
      responses_needed: responsesNeeded,
      responses_sent: totalResponsesSent,
      response_rate: responseRate,
      threshold: THRESHOLD,
      below_threshold_by: THRESHOLD - responseRate
    }
  });
}

// Limit to avoid API overload
if (candidates.length === 0) {
  return [{ json: { no_results: true, message: 'No members need outreach (all compliant or recently contacted)' } }];
}

// Return limited set for processing
return candidates.slice(0, MAX_PER_RUN);

// Process ALL items, not just first
const allInputs = $input.all();
const allEprData = $('Filter Candidates').all();
const results = [];

for (let i = 0; i < allInputs.length; i++) {
  const input = allInputs[i].json;
  const eprData = allEprData[i]?.json || {};

  if (!input.results || input.results.length === 0) {
    results.push({
      json: {
        ...eprData,
        hubspot_found: false,
        skip_reason: 'Station code not found in HubSpot'
      }
    });
  } else {
    results.push({
      json: {
        ...eprData,
        hubspot_found: true,
        hubspot_station_id: input.results[0].id
      }
    });
  }
}

return results;

// Get HTTP response from current item
const apiResponse = $input.item.json;

// Get paired item from the node RIGHT BEFORE the HTTP node (Found? TRUE branch)
// The IF node passes through all json data, so this has our EPR data
const previousData = $('Process Search').item.json;

const companyId = apiResponse.results?.[0]?.toObjectId || null;

return {
  json: {
    ...previousData,
    company_id: companyId
  }
};

const owner = $input.item.json;
const company = $('Get Company').item.json;
const extractData = $('Extract Company ID').item.json;

const ownerEmail = (owner.email || '').toLowerCase();
const membershipState = (company.properties?.membership_state || 'California').toLowerCase();

// Normalize state to CA or NV
let state = 'CA';
if (membershipState.includes('nevada') || membershipState === 'nv') {
  state = 'NV';
}

if (ownerEmail === 'nick.white@usan.org') {
  return {
    json: {
      ...extractData,
      skip: true,
      skip_reason: 'Nick company - excluded from automation',
      owner_email: ownerEmail,
      company_name: company.properties?.name || '',
      state: state
    }
  };
} else {
  return {
    json: {
      ...extractData,
      skip: false,
      owner_email: ownerEmail,
      company_name: company.properties?.name || '',
      owner_id: company.properties?.hubspot_owner_id,
      state: state
    }
  };
}

const apiResponse = $input.item.json;  // From Get Contacts HTTP
const previousData = $('Check Owner').item.json;  // Paired item

const memberRep = apiResponse.results?.find(a => 
  a.associationTypes?.some(t => t.typeId === 36 || t.label === 'Member Representative')
);

const contactId = memberRep?.toObjectId || apiResponse.results?.[0]?.toObjectId;

if (!contactId) {
  return {
    json: {
      ...previousData,
      contact_found: false,
      skip_reason: 'No contact found'
    }
  };
} else {
  return {
    json: {
      ...previousData,
      contact_found: true,
      contact_id: contactId
    }
  };
}

const contact = $input.item.json;  // From Get Contact Details HTTP
const previousData = $('Find Contact').item.json;  // Paired item

const firstName = contact.properties?.firstname || (previousData.member_name || '').split(' ')[0];
const email = contact.properties?.email;

if (!email) {
  return {
    json: {
      ...previousData,
      skip: true,
      skip_reason: 'Contact has no email'
    }
  };
} else {
  return {
    json: {
      ...previousData,
      first_name: firstName,
      last_name: contact.properties?.lastname || '',
      email: email,
      contact_name: `${firstName} ${contact.properties?.lastname || ''}`.trim()
    }
  };
}

const data = $input.item.json;

// ============ TEST MODE CONFIG ============
const TEST_MODE = true;
const TEST_EMAIL = 'christian.olesen@usan.org';
// ==========================================

// Skip if no email or already marked skip
if (!data.email || data.skip) {
  return { json: { ...data, skip: true } };
}

// ============ REP DETAILS ============
const REP_DETAILS = {
  'christian.olesen@usan.org': { name: 'Christian Olesen', title: 'Member Services Specialist', phone: 'REDACTED_PHONE', calendly: 'https://calendly.com/christian-olesen-usan/30min', calendlyText: "Christian's Availability" },
  'germain.suess@usan.org': { name: 'Germain Suess', title: 'Member Services Specialist', phone: 'REDACTED_PHONE', calendly: 'https://calendly.com/germain-usan/yearly-membership-review', calendlyText: "Germain's Availability" },
  'trevor.harris@usan.org': { name: 'Trevor Harris', title: 'Member Services Lead', phone: 'REDACTED_PHONE', calendly: 'https://calendly.com/trevor-harris-kr8/yearly-membership-review', calendlyText: "Trevor's Availability" }
};

// ============ STATE TEMPLATES ============
const STATE_CONFIG = {
  'CA': {
    legalCitation: '4216.3.(c) (1) (A) Every operator shall supply an electronic positive response through the regional notification center before the legal excavation start date and time.',
    legalUrl: 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=GOV&division=5.&title=1.&part=&chapter=3.1.&article=2',
    legalName: 'California Government Code 4216',
    complianceWarning: 'By being out of compliance, <strong>mandatory training and/or fines can be imposed by the Underground Safety Board</strong>.',
    portalUrl: 'https://appsca.undergroundservicealert.org/pcadmin/Account/Login',
    portalName: 'CA DPP Login'
  },
  'NV': {
    legalCitation: 'Please monitor the tickets that require Electronic Positive Responses within the Damage Prevention Portal (DPP) as required by NRS 455.',
    legalUrl: 'https://www.leg.state.nv.us/nrs/nrs-455.html',
    legalName: 'Nevada Revised Statutes 455',
    complianceWarning: 'The Nevada Public Utilities Commission (PUC) monitors EPR compliance and may investigate members not utilizing the EPR system, which could result in potential fines.',
    portalUrl: 'https://appsnv.undergroundservicealert.org/pcadmin/Account/Login',
    portalName: 'NV DPP Login'
  }
};

const LOGO_URL = 'https://i.imgur.com/v6diEdK.jpg';
const BANNER_URL = 'https://i.imgur.com/HfkbUwp.png';

// ============ REP LIMIT CHECK ============
const staticData = $getWorkflowStaticData('global');
if (!staticData.repCounts) staticData.repCounts = {};

const ownerEmail = (data.owner_email || '').toLowerCase();
const rep = REP_DETAILS[ownerEmail] || REP_DETAILS['christian.olesen@usan.org'];
const repKey = ownerEmail || 'christian.olesen@usan.org';

staticData.repCounts[repKey] = (staticData.repCounts[repKey] || 0) + 1;

if (staticData.repCounts[repKey] > 10) {
  return { json: { ...data, skip: true, skip_reason: `Rep ${rep.name} has reached 10 emails this run`, rep_name: rep.name } };
}

// ============ STATE CONFIG ============
const state = data.state || 'CA';
const stateConfig = STATE_CONFIG[state] || STATE_CONFIG['CA'];

// ============ GAUGE CHART ============
const responseRate = parseInt(data.response_rate) || 0;
const gaugeColor = responseRate >= 90 ? '%234CAF50' :
                   responseRate >= 75 ? '%238BC34A' :
                   responseRate >= 50 ? '%23FFC107' :
                   responseRate >= 20 ? '%23FF9800' :
                   '%23F44336';

const gaugeConfig = {
  type: 'radialGauge',
  data: { datasets: [{ data: [responseRate], backgroundColor: gaugeColor.replace(/%23/g, '#') }] },
  options: { 
    centerPercentage: 80,
    centerArea: { text: responseRate + '%', fontColor: '#333', fontSize: 24 },
    trackColor: '#e0e0e0'
  }
};
const gaugeUrl = 'https://quickchart.io/chart?c=' + encodeURIComponent(JSON.stringify(gaugeConfig)) + '&w=200&h=200';

// Grade message based on response rate
let gradeMessage = '';
let gradeColor = '#333';
if (responseRate >= 90) {
  gradeMessage = 'Compliant';
  gradeColor = '#4CAF50';
} else if (responseRate >= 75) {
  gradeMessage = 'Almost There';
  gradeColor = '#8BC34A';
} else if (responseRate >= 50) {
  gradeMessage = 'Needs Improvement';
  gradeColor = '#FFC107';
} else if (responseRate >= 20) {
  gradeMessage = 'Needs Attention';
  gradeColor = '#FF9800';
} else {
  gradeMessage = 'Critical - Action Required';
  gradeColor = '#F44336';
}

// ============ SIGNATURE ============
const SIGNATURE_HTML = `<p style="font-family: Aptos, sans-serif; font-size: 12pt;">Thank you,</p><br><table cellspacing="0" cellpadding="0" style="border-collapse: collapse;"><tr><td style="padding-right: 15px; vertical-align: top; border-right: 1.5pt solid #000;"><img src="${LOGO_URL}" alt="USAN 811" width="175" style="max-width: 175px;"></td><td style="padding-left: 15px; vertical-align: top;"><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;"><b>${rep.name}</b></p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;">${rep.title}</p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;">${rep.phone}</p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;"><a href="http://www.undergroundservicealert.org/" style="color: #0563c1;">undergroundservicealert.org</a></p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;">4005 Port Chicago Hwy #100 Concord, CA 94520</p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;"><a href="${rep.calendly}" style="color: #4c94d8;"><b>${rep.calendlyText}</b></a></p></td></tr></table><br><a href="https://www.undergroundservicealert.org/damage-prevention-portal/"><img src="${BANNER_URL}" alt="NEW Damage Prevention Portal" width="450" style="max-width: 450px;"></a><br><br><p style="font-size: 9pt; color: #666; font-family: Aptos, sans-serif;">This message contains confidential information and is intended only for the intended recipients. If you are not an intended recipient you should not disseminate, distribute or copy this e-mail. Please notify us immediately by e-mail if you have received this e-mail by mistake and delete this e-mail from your system.</p>`;

// ============ BUILD EMAIL BODY ============
const emailBody = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">
<p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;"><strong>${data.first_name}</strong>,</p>

<div style="text-align: center; margin: 20px 0; padding: 20px; background: #f5f5f5; border-radius: 8px;">
  <img src="${gaugeUrl}" alt="Your EPR Score: ${responseRate}%" width="200" height="200" style="display: block; margin: 0 auto;">
  <p style="font-size: 16pt; font-weight: bold; color: ${gradeColor}; margin: 10px 0 5px 0;">${gradeMessage}</p>
  <p style="font-size: 11pt; color: #666; margin: 0;">Your EPR Response Rate: <strong>${responseRate}%</strong></p>
  <p style="font-size: 10pt; color: #888; margin: 5px 0 0 0;">(${data.responses_sent} of ${data.responses_needed} responses)</p>
</div>

<p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">Just reaching out because Electronic Positive Responses are still not being posted on the tickets that <strong>${data.member_name}</strong> is receiving.</p>

<p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt; margin: 15px 0; padding: 10px; border-left: 3px solid #ccc; background: #f9f9f9;"><em>${stateConfig.legalCitation}</em> — <a href="${stateConfig.legalUrl}">${stateConfig.legalName}</a></p>

<p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">${stateConfig.complianceWarning}</p>

<p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">To post EPR on the tickets that you receive please login to the Damage Prevention Portal and follow the instructions in our video:</p>

<ul style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">
<li><strong>${stateConfig.portalName}:</strong> <a href="${stateConfig.portalUrl}">${stateConfig.portalUrl}</a></li>
<li><strong>How to use Electronic Positive Response:</strong> <a href="https://www.youtube.com/watch?v=c1b6HlX-fx4">https://www.youtube.com/watch?v=c1b6HlX-fx4</a></li>
</ul>

<p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">If you would like to schedule a meeting with me, here is my availability: <a href="${rep.calendly}"><strong>Schedule a Meeting</strong></a></p>

<p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">Please let me know if you have any questions.</p>

${SIGNATURE_HTML}
</body></html>`;

// ============ FINALIZE ============
let subject = `${data.first_name}, EPR Compliance - Action Required (${responseRate}%)`;
let finalEmail = data.email;
let finalBody = emailBody;

if (TEST_MODE) {
  finalEmail = TEST_EMAIL;
  subject = `[TEST-${state}] ${subject}`;
  const testBanner = `<div style="background-color: #ff6b6b; color: white; padding: 15px; margin-bottom: 20px; border-radius: 5px; font-family: Arial, sans-serif;"><strong>TEST MODE - This email would be sent to:</strong><br><strong>Recipient:</strong> ${data.email}<br><strong>Contact:</strong> ${data.contact_name || data.first_name}<br><strong>Member:</strong> ${data.member_name}<br><strong>Rep:</strong> ${rep.name}<br><strong>State:</strong> ${state}</div>`;
  finalBody = emailBody.replace('<body style="font-family:', '<body style="font-family:').replace('11pt;">', '11pt;">' + testBanner);
}

return { 
  json: { 
    ...data, 
    skip: false, 
    email: finalEmail, 
    original_email: data.email, 
    email_subject: subject, 
    email_body: finalBody, 
    rep_name: rep.name, 
    state: state,
    test_mode: TEST_MODE 
  } 
};

// Mailgun output has no data - get it from Should Send? using paired item
const mailgunResponse = $input.item.json;
const emailData = $('Should Send?').item.json;

const now = new Date().toISOString();

return {
  json: {
    member_name: emailData.member_name,
    station_code: emailData.station_code,
    email: emailData.original_email || emailData.email,
    sent_to: emailData.email,
    contact_name: emailData.contact_name,
    response_rate: emailData.response_rate,
    rep_name: emailData.rep_name,
    status: emailData.test_mode ? 'test_sent' : 'sent',
    sent_at: now
  }
};

const emailData = $('Should Send?').item.json;
const now = new Date().toISOString();

return {
  json: {
    member_name: emailData.member_name,
    station_code: emailData.station_code,
    email: emailData.email || 'N/A',
    response_rate: emailData.response_rate,
    rep_name: emailData.rep_name || 'N/A',
    status: 'send_failed',
    sent_at: now
  }
};

// Process ALL items
const allInputs = $input.all();
const now = new Date().toISOString();
const results = [];

for (const item of allInputs) {
  const data = item.json;
  results.push({
    json: {
      member_name: data.member_name || 'N/A',
      station_code: data.station_code || 'N/A',
      response_rate: data.response_rate || 'N/A',
      rep_name: data.rep_name || 'N/A',
      status: 'skipped',
      skip_reason: data.skip_reason || 'Unknown',
      processed_at: now
    }
  });
}

return results;
